1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation, 0 neighbors)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (underpopulation, 1 neighbor each)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block stable (each cell has 3 neighbors)", () => {
15	    const sortCells = (cells: [number, number][]) =>
16	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
17	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
18	    const expected: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
19	    expect(sortCells(nextGeneration(input))).toEqual(sortCells(expected));
20	  });
21	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
22	    const sortCells = (cells: [number, number][]) =>
23	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
24	    const input: [number, number][] = [[0, 0], [0, 1], [0, 2]];
25	    const expected: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
26	    expect(sortCells(nextGeneration(input))).toEqual(sortCells(expected));
27	  });
28	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
29	    const sortCells = (cells: [number, number][]) =>
30	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
31	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
32	    const expected: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
33	    expect(sortCells(nextGeneration(input))).toEqual(sortCells(expected));
34	  });
35	  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
36	});
37

1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	export const nextGeneration = (cells: Cell[]): Cell[] => {
10	  const liveCellKeys = new Set(cells.map(([x, y]) => `${x},${y}`));
11	  const isAlive = (x: number, y: number): boolean => liveCellKeys.has(`${x},${y}`);
12	
13	  const countNeighbors = (x: number, y: number): number =>
14	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isAlive(x + dx, y + dy)).length;
15	
16	  const candidateKeys = new Set<string>();
17	  const candidates: Cell[] = [];
18	  for (const [x, y] of cells) {
19	    for (const [dx, dy] of [[0, 0], ...NEIGHBOR_OFFSETS] as Cell[]) {
20	      const cx = x + dx;
21	      const cy = y + dy;
22	      const key = `${cx},${cy}`;
23	      if (!candidateKeys.has(key)) {
24	        candidateKeys.add(key);
25	        candidates.push([cx, cy]);
26	      }
27	    }
28	  }
29	
30	  return candidates.filter(([x, y]) => {
31	    const neighborCount = countNeighbors(x, y);
32	    if (isAlive(x, y)) {
33	      return neighborCount === 2 || neighborCount === 3;
34	    }
35	    return neighborCount === 3;
36	  });
37	};
